from xml.etree import ElementTree as ET

def parse_xml_config(filename):
    tree = ET.parse(filename)
    root = tree.getroot()

    settings = {}
    for element in root.findall('setting'):
        name = element.attrib['name']
        value = element.text.strip()
        settings[name] = value

    return settings